SELECT [Purchase Line].[Document Type], Item.[Line Code] AS Linea, [Purchase Line].[Model Item No_] AS Articolo, [Purchase Line].[Variable Code 01] AS CodiceColore, [Variable Code].Description AS Colore, Item.[Trademark Code] AS Marchio, [Purchase Header].[Selling Season Code] AS Stagione, [Purchase Line].[delete reason], Sum(Val([quantity])) AS PaiaComprate, Item.Description AS Descrizione, Item.[Description 2] AS Descrizione2, Item.[Product Family] AS FamigliaProdotto, Item.[Product Sex] AS GenereProdotto, Item.[Collection Code] AS [Collection Code], Item.[Vendor No_], Vendor.Name AS VendorName, Item.Manufacturer, Vendor_1.Name AS ManufacturerName
FROM ((([Purchase Line] INNER JOIN (Item LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) ON [Purchase Line].[Model Item No_] = Item.No_) INNER JOIN [Variable Code] ON ([Purchase Line].[Variable Code 01] = [Variable Code].[Variable Code]) AND ([Purchase Line].[Variable Group 01] = [Variable Code].[Variable Group])) INNER JOIN [Purchase Header] ON [Purchase Line].[Document No_] = [Purchase Header].No_) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_
WHERE (((Item.[advertising material])=0))
GROUP BY [Purchase Line].[Document Type], Item.[Line Code], [Purchase Line].[Model Item No_], [Purchase Line].[Variable Code 01], [Variable Code].Description, Item.[Trademark Code], [Purchase Header].[Selling Season Code], [Purchase Line].[delete reason], Item.Description, Item.[Description 2], Item.[Product Family], Item.[Product Sex], Item.[Collection Code], Item.[Vendor No_], Vendor.Name, Item.Manufacturer, Vendor_1.Name
HAVING ((([Purchase Line].[Document Type])=1) AND ((Item.[Trademark Code])=[Maschere]![principale]![filtroMarchio]) AND (([Purchase Header].[Selling Season Code])=[Maschere]![principale]![filtroStagione]) AND (([Purchase Line].[delete reason])=""))
ORDER BY Sum(Val([quantity])) DESC;

